#nullable enable // autogenerated

using MVZ2Logic.Options;
using PVZEngine;

namespace MVZ2Logic.Commands
{
    [PropertyRegistryRegion(LogicPropertyRegions.optionWidget)]
    public static class LogicOptionWidgetProps
    {
        private static PropertyMeta<T> Get<T>(string name)
        {
            return new PropertyMeta<T>(name);
        }

        #region 标签
        public static readonly PropertyMeta<string> LABEL = Get<string>("label");
        public static string? GetLabel(this OptionWidgetDefinition def) => def.GetProperty<string>(LABEL);
        #endregion

        #region 工具提示
        public static readonly PropertyMeta<string> TOOLTIP = Get<string>("tooltip");
        public static string? GetTooltip(this OptionWidgetDefinition def) => def.GetProperty<string>(TOOLTIP);
        #endregion

        #region 分类ID
        public static readonly PropertyMeta<NamespaceID> CATEGORY_ID = Get<NamespaceID>("category_id");
        public static NamespaceID? GetCategoryID(this OptionWidgetDefinition def) => def.GetProperty<NamespaceID>(CATEGORY_ID);
        #endregion

        #region 滑动条
        public static readonly PropertyMeta<bool> SLIDER_WHOLE_NUMBERS = Get<bool>("slider_whole_numbers");
        public static bool IsSliderWholeNumbers(this OptionWidgetDefinition def) => def.GetProperty<bool>(SLIDER_WHOLE_NUMBERS);
        public static readonly PropertyMeta<float> SLIDER_MIN_VALUE = Get<float>("slider_min_value");
        public static float GetSliderMinValue(this OptionWidgetDefinition def) => def.GetProperty<float>(SLIDER_MIN_VALUE);
        public static readonly PropertyMeta<float> SLIDER_MAX_VALUE = Get<float>("slider_max_value");
        public static float GetSliderMaxValue(this OptionWidgetDefinition def) => def.GetProperty<float>(SLIDER_MAX_VALUE);
        #endregion

        #region 工具提示
        public static readonly PropertyMeta<int> ORDER = Get<int>("order");
        public static int GetOrder(this OptionWidgetDefinition def) => def.GetProperty<int>(ORDER);
        #endregion

    }
}
